package grpc

import (
	"context"
	"crypto/hmac"
	"errors"
	"fmt"
	"math"
	"strconv"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
	"github.com/utilitywarehouse/uwos-go/telemetry/tracing"
	"github.com/utilitywarehouse/uwos-go/telemetry/uwconv"
	"go.opentelemetry.io/otel/attribute"
	"go.opentelemetry.io/otel/trace"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
	"google.golang.org/protobuf/types/known/emptypb"
	"google.golang.org/protobuf/types/known/timestamppb"

	"github.com/utilitywarehouse/telecom-mobile/pkg/generated/protos/mobile/v1/events/serviceevents"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/terrors"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/models"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/pkg/protos/generated/v1/apis/handset"
)

var (
	requestCounter = promauto.NewCounterVec(prometheus.CounterOpts{
		Name: "handset_api_requests_total",
		Help: "Total number of handset API requests by method and status",
	}, []string{"method", "status"})

	callbackCounter = promauto.NewCounterVec(prometheus.CounterOpts{
		Name: "handset_eligibility_callback_total",
		Help: "Total number of eligibility callbacks by result",
	}, []string{"result"})
)

const callbackSecretHeaderKey = "x-callback-secret" // nolint: gosec

//go:generate mockgen -destination=./mocks/$GOFILE -source=./$GOFILE

type Service interface {
	GetActiveContractForService(ctx context.Context, serviceID string) (*models.Contract, error)
