const currencyGBP = "GBP"

//go:generate mockgen -destination=./mocks/$GOFILE -source=./$GOFILE

type Storage interface {
	UpsertHandsetModel(ctx context.Context, handset models.Handset) error
	GetHandsets(ctx context.Context, isInStock bool) ([]models.Handset, error)
	GetHandsetByID(ctx context.Context, handsetID uuid.UUID) (*models.Handset, error)
	CreateContract(ctx context.Context, contract models.Contract) error
	GetContractByRequestID(ctx context.Context, requestID string) (*models.Contract, error)
	GetActiveContractForService(ctx context.Context, serviceID string) (*models.Contract, error)
	UpdateContractStatus(ctx context.Context, requestID string, status models.ContractStatus) error
	UpdateContractStatusByID(ctx context.Context, contractID uuid.UUID, status models.ContractStatus) error
	UpdateContractEligibilityApproved(ctx context.Context, requestID string, outcome models.EligibilityOutcome) error
	UpdateContractEligibilityFailed(ctx context.Context, requestID string, outcome models.EligibilityFailureOutcome) error
	UpdateContractLoanReference(ctx context.Context, requestID string, loanReference string) error
	UpdateContractBankDetails(ctx context.Context, requestID string, bankAccountNumber string, bankTitle string) error
	CustomerHasDeclinedContract(ctx context.Context, customerID string, since time.Duration) (bool, error)
}

type EventProducer interface {
	ProduceMobileHandsetContractRequestedSync(ctx context.Context, out *serviceevents.MobileHandsetContractRequested) error
	ProduceMobileHandsetContractApprovedSync(ctx context.Context, out *serviceevents.MobileHandsetContractApproved) error
	ProduceMobileHandsetContractDeclinedSync(ctx context.Context, out *serviceevents.MobileHandsetContractDeclined) error
}

type AccountClient interface {
	GetAccount(ctx context.Context, in *accountgateway.GetAccountRequest, opts ...grpc.CallOption) (*accountgateway.GetAccountResponse, error)
}

type MyServicesClient interface {
	GetServices(ctx context.Context, in *myservicesapi.GetServicesRequest, opts ...grpc.CallOption) (*myservicesapi.Services, error)
}

type Service struct {
	store                  Storage
	eventProducer          EventProducer
	accountClient          AccountClient
	myServicesClient       MyServicesClient
	eligibilityProviderURL string
	backoffPeriod          time.Duration
}

func NewService(store Storage, eventProducer EventProducer, accountClient AccountClient, myServicesClient MyServicesClient, eligibilityProviderURL string, backoffPeriod time.Duration) *Service {
	return &Service{
		store:                  store,
		eventProducer:          eventProducer,
		accountClient:          accountClient,
		myServicesClient:       myServicesClient,
		eligibilityProviderURL: eligibilityProviderURL,
		backoffPeriod:          backoffPeriod,
	}
}

