func (s *Service) GetRequest(ctx context.Context, requestID string) (*models.Contract, *models.Handset, error) {
	if requestID == "" {
		return nil, nil, fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
	}

	contract, err := s.store.GetContractByRequestID(ctx, requestID)
	if err != nil {
		if errors.Is(err, terrors.ErrNotFound) {
			return nil, nil, fmt.Errorf("contract not found for request_id: %w", terrors.ErrNotFound)
		}
		return nil, nil, fmt.Errorf("failed to get contract by request_id: %w", err)
	}

	// If the contract already has all handset details captured at creation time, use them directly
	// without a storage lookup. This preserves the pricing agreed at time of request.
	if contract.HandsetName != "" && contract.ContractPrice != "" && contract.RetailPrice != "" && contract.ContractMonths != "" {
		return contract, nil, nil
	}

	handsetUUID, err := uuid.Parse(contract.HandsetID)
	if err != nil {
		return nil, nil, fmt.Errorf("invalid handset id on contract: %w", err)
	}

	h, err := s.store.GetHandsetByID(ctx, handsetUUID)
	if err != nil {
		return nil, nil, fmt.Errorf("failed to get handset for contract: %w", err)
	}

	if h.CurrentProperties.RRPPence == 0 || h.CurrentProperties.RentalPricePence == 0 || h.CurrentProperties.ContractTermMonths == 0 {
		return nil, nil, fmt.Errorf("handset has incomplete pricing data: %w", terrors.ErrFailedValidation)
	}

	// If contract has a specific version, find that version's properties
	if contract.HandsetVersion != "" && contract.HandsetVersion != h.CurrentProperties.Version {
		for _, v := range h.Versions {
			if v.Version == contract.HandsetVersion {
				h.CurrentProperties = v
				break
			}
		}
	}

	return contract, h, nil
}

func (s *Service) GetActiveContractForService(ctx context.Context, serviceID string) (*models.Contract, error) {
	if serviceID == "" {
		return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
	}

	contract, err := s.store.GetActiveContractForService(ctx, serviceID)
	if err != nil {
		if errors.Is(err, terrors.ErrNotFound) {
			return nil, fmt.Errorf("no active contract found for service: %w", terrors.ErrNotFound)
		}
		return nil, fmt.Errorf("failed to get active contract: %w", err)
	}

	return contract, nil
}

func (s *Service) RequestHandsetForService(ctx context.Context, serviceID, customerID, handsetID string) (string, string, error) {
	if serviceID == "" || customerID == "" || handsetID == "" {
		return "", "", fmt.Errorf("service_id, customer_id, and handset_id are required: %w", terrors.ErrBadRequest)
	}

	handsetUUID, err := uuid.Parse(handsetID)
	if err != nil {
		return "", "", fmt.Errorf("invalid handset_id: %w", terrors.ErrBadRequest)
	}

	// Check service belongs to customer
	servicesResp, err := s.myServicesClient.GetServices(ctx, &myservicesapi.GetServicesRequest{
		CustomerId:   customerID,
		IncludeEnded: true,
	})
	if err != nil {
		return "", "", fmt.Errorf("failed to retrieve services for customer: %w", err)
	}

	found := false
	for _, svc := range servicesResp.Services {
		if svc.GetMobileService() != nil && svc.GetMobileService().GetServiceId() == serviceID {
			found = true
			if svc.GetMobileService().GetState() != serviceevents.MobileService_LIVE {
				return "", "", fmt.Errorf("service is not active: %w", terrors.ErrFailedValidation)
			}
			break
		}
	}
	if !found {
		return "", "", fmt.Errorf("service not found for customer: %w", terrors.ErrNotFound)
	}

	// Check for existing active contract
	_, err = s.store.GetActiveContractForService(ctx, serviceID)
	if err == nil {
		return "", "", fmt.Errorf("an active handset contract already exists for this service: %w", terrors.ErrFailedValidation)
	}
	if !errors.Is(err, terrors.ErrNotFound) {
		return "", "", fmt.Errorf("failed to check active contract: %w", err)
	}

	err = s.checkPreEligibility(ctx, customerID)
	if err != nil {
		return "", "", fmt.Errorf("failed pre-eligibility checks: %w", err)
	}

	// Verify handset exists and is in stock
	h, err := s.store.GetHandsetByID(ctx, handsetUUID)
	if err != nil {
		return "", "", fmt.Errorf("handset not found: %w", terrors.ErrNotFound)
	}
	if !h.Active {
		return "", "", fmt.Errorf("handset is not active: %w", terrors.ErrFailedValidation)
	}
	if h.QuantityInStock <= 0 {
		return "", "", fmt.Errorf("handset is out of stock: %w", terrors.ErrFailedValidation)
	}

	// Fetch customer information from account-gateway
	accountResp, err := s.accountClient.GetAccount(ctx, &accountgateway.GetAccountRequest{
		AccountId: customerID,
	})
	if err != nil {
		return "", "", fmt.Errorf("failed to retrieve account: %w", err)
	}
	if accountResp.GetAccount() == nil {
		return "", "", fmt.Errorf("account response missing account data")
	}

	now := time.Now()
	props := h.CurrentProperties
	contract := models.Contract{
		ID:             uuid.New(),
		ServiceID:      serviceID,
		CustomerID:     customerID,
		HandsetID:      handsetID,
		HandsetName:    fmt.Sprintf("%s %s", props.Manufacturer, props.Model),
		HandsetVersion: props.Version,
		ContractPrice:  fmt.Sprintf("%d", props.RentalPricePence),
		RetailPrice:    fmt.Sprintf("%d", props.RRPPence),
		ContractMonths: fmt.Sprintf("%d", props.ContractTermMonths),
		RequestID:      uuid.New().String(),
		Status:         models.ContractStatusPendingEligibility,
		CreatedAt:      now,
		UpdatedAt:      now,
	}

	if err = s.store.CreateContract(ctx, contract); err != nil {
		return "", "", fmt.Errorf("failed to create contract: %w", err)
	}

	tlog.WithAttribute("service_id", contract.ServiceID).
		WithAttribute("customer_id", contract.CustomerID).
		WithAttribute("contract_id", contract.ID.String()).
		WithAttribute("request_id", contract.RequestID).
		WithAttribute("handset_id", contract.HandsetID).
		Info(ctx, "handset contract created")

	// Produce lifecycle event
	if err := s.eventProducer.ProduceMobileHandsetContractRequestedSync(ctx, &serviceevents.MobileHandsetContractRequested{
		ServiceId:  contract.ServiceID,
		CustomerId: contract.CustomerID,
		ContractId: contract.ID.String(),
		HandsetId:  contract.HandsetID,
	}); err != nil {
		tlog.WithError(err).
			WithAttribute("contract_id", contract.ID.String()).
			Error(ctx, "failed to produce MobileHandsetContractRequested event")
	}

	redirectURL, err := eligibilityRedirectURL(s.eligibilityProviderURL, contract.RequestID)
	if err != nil {
		return "", "", err
	}

	return contract.RequestID, redirectURL, nil
}

