// helper to build a GetServices response with a single LIVE mobile service
func liveServiceResponse(serviceID string) *myservicesapi.Services {
	return &myservicesapi.Services{
		Services: []*myservicesapi.MobileService{
			{
				MobileService: &serviceevents.MobileService{
					ServiceId: serviceID,
					State:     serviceevents.MobileService_LIVE,
				},
			},
		},
	}
}

// helper to create a 1-hour time.Duration
func oneHourDuration() time.Duration {
	d, _ := time.ParseDuration("1h")
	return d
}

var _ = Describe("GetAvailableHandsets", func() {
	var (
		ctrl      *gomock.Controller
		mockStore *mockService.MockStorage
		svc       *service.Service
		ctx       context.Context
	)

	BeforeEach(func() {
		ctrl = gomock.NewController(GinkgoT())
		mockStore = mockService.NewMockStorage(ctrl)
		svc = service.NewService(mockStore, nil, nil, nil, "", oneHourDuration())
		ctx = context.Background()
	})

	AfterEach(func() {
		ctrl.Finish()
	})

	When("service_id is empty", func() {
		It("returns a bad request error", func() {
			_, err := svc.GetAvailableHandsets(ctx, "", "")
			Expect(err).To(HaveOccurred())
			Expect(errors.Is(err, terrors.ErrBadRequest)).To(BeTrue())
		})
	})

	When("an active contract already exists", func() {
		It("returns nil (empty list)", func() {
			mockStore.EXPECT().
				GetActiveContractForService(gomock.Any(), "service-1").
				Return(&models.Contract{}, nil)

			handsets, err := svc.GetAvailableHandsets(ctx, "customer-1", "service-1")
			Expect(err).ToNot(HaveOccurred())
			Expect(handsets).To(BeNil())
		})
	})

	When("checking active contract fails with unexpected error", func() {
		It("returns the error", func() {
			mockStore.EXPECT().
				GetActiveContractForService(gomock.Any(), "service-1").
				Return(nil, errors.New("db error"))

			_, err := svc.GetAvailableHandsets(ctx, "customer-1", "service-1")
			Expect(err).To(HaveOccurred())
			Expect(err.Error()).To(ContainSubstring("db error"))
		})
	})

	When("no active contract but declined contract exists", func() {
		It("returns no handsets", func() {
			mockStore.EXPECT().
				GetActiveContractForService(gomock.Any(), "service-1").
				Return(nil, terrors.ErrNotFound)

			mockStore.EXPECT().
				CustomerHasDeclinedContract(gomock.Any(), "customer-1", oneHourDuration()).
				Return(true, nil)

			handsets, err := svc.GetAvailableHandsets(ctx, "customer-1", "service-1")
			Expect(err).To(HaveOccurred())
			Expect(handsets).To(BeNil())
		})
	})

	When("no active contract or declined contract exists", func() {
		It("returns available handsets", func() {
			mockStore.EXPECT().
				GetActiveContractForService(gomock.Any(), "service-1").
				Return(nil, terrors.ErrNotFound)

			mockStore.EXPECT().
				CustomerHasDeclinedContract(gomock.Any(), "customer-1", oneHourDuration()).
				Return(false, nil)

			mockStore.EXPECT().
				GetHandsets(gomock.Any(), true).
				Return([]models.Handset{
					{
						ID:     testHandsetUUID,
						Active: true,
						CurrentProperties: models.HandsetProperties{
							Name:               "iPhone 15",
							RentalPricePence:   4200,
							RRPPence:           99900,
							ContractTermMonths: 24,
						},
					},
				}, nil)

			handsets, err := svc.GetAvailableHandsets(ctx, "customer-1", "service-1")
			Expect(err).ToNot(HaveOccurred())
			Expect(handsets).To(HaveLen(1))
			Expect(handsets[0].ID).To(Equal(testHandsetUUID))
			Expect(handsets[0].CurrentProperties.Name).To(Equal("iPhone 15"))
		})
	})
})

